def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 5, -1):
                for b in range(1, a+4):
                    component = ((ratio - a) ** 7) / (a * b * 1.1 + 0.5)
                    priority += component * np.sin(ratio * b / (a + 0.5))
            priority += (np.exp(ratio - 10) * np.cos(ratio * 1.3)) ** 2
            if bin_cap < item * 0.3:
                priority += np.log1p(bin_cap * item) * 7
            else:
                priority -= np.exp(-ratio) * 10
        elif 6 < ratio <= 10:
            acc = 0
            for p in range(2, int(np.floor(ratio)) + 5):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 4) * np.tanh(ratio * p / (q + 1))
                    acc += np.sin(val * 3) / (q + 1.5)
            priority = acc + np.sqrt(ratio) * 8 - np.tanh(ratio - 6) * 3
            if bin_cap < item * 1.5:
                priority += np.exp(-bin_cap/item) * 5
            else:
                priority -= np.log1p(ratio)
        elif 3 <= ratio <= 6:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 3) ** r) / (r ** 2 + 1) * np.cos(r * ratio)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (6 - ratio)) * 2
            for idx_mod in [i % 2, i % 5]:
                if idx_mod == 0:
                    priority += np.sin(ratio * idx_mod * 2) * 1.2
                else:
                    priority -= np.cos(ratio * idx_mod * 3) * 1.2
        elif 1 <= ratio < 3:
            s1 = 0
            s2 = 0
            for n in range(1, 12):
                s1 += ((3 - ratio) ** n) / (n * 3) * np.tanh(n * ratio)
            for m in range(1, 6):
                s2 += np.cos(m * ratio * i) / (m ** 1.5 + 0.5)
            priority = s1 + s2 + np.exp(-1 / (ratio + 0.1)) * 4
            if bin_cap > item * 2:
                priority -= np.log(bin_cap + 1) * 3
            else:
                priority += np.sqrt(bin_cap) * 2.5
        elif 0.5 <= ratio < 1:
            s = 0
            for k in range(1, 20):
                s += ((1 - ratio) ** k) / (k * 2) * np.sin(k * ratio * 1.5)
            penalty = 0
            if bin_cap < item * 0.7:
                penalty = np.exp(-item / (bin_cap + 0.7)) * 6
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty
            for t in range(1, 5):
                priority += np.tanh(t * ratio * i) * ((ratio - 0.5) ** t) / t
        elif 0.2 <= ratio < 0.5:
            s = 0
            for u in range(1, 25):
                s += ((0.5 - ratio) ** u) / (u + 1) * np.cos(u * item * 2)
            priority = s * np.log1p(bin_cap) - (bin_cap / (item + 1)) * 2
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.sin(bin_cap * 1.2) * 1.5
            else:
                priority /= (np.sqrt(bin_cap) + 1)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for v in range(1, 18):
                s += ((0.2 - ratio) ** v) / (v * 5) * np.cos(v * ratio * 2.5)
            priority = s + 3 / (bin_cap + 2)
            if int(item * 2) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for w in range(1, 9):
                priority += ((0.2 - ratio) ** w) / (w * 8) * np.sin(item * w * 0.9)
        else:
            s = 0
            for z in range(1, 15):
                s += ((0.05 - ratio) ** z) / (z * 9) * np.sin(z * item * 1.1)
            priority = s + 4 / (bin_cap + 1)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.05:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
        if bin_cap < item * 0.4:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 6
        for idx_offset in range(1, 6):
            val = ratio * (i + idx_offset ** 2)
            if (i + idx_offset) % 4 == 0:
                priority += np.sin(val) * 0.5
            else:
                priority -= np.cos(val) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        priorities[i] = priority
    return priorities
